### 6. **No HTTPS Enforcement** (Medium-High)
**OWASP: A02:2021 – Cryptographic Failures**

**Issue:** Server listens on HTTP without requiring HTTPS:

```javascript
// ❌ VULNERABLE - HTTP only, no encryption
app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

**Recommendation:**
```javascript
// ✅ CORRECT - Enforce HTTPS in production
const https = require('https');
const fs = require('fs');

if (process.env.NODE_ENV === 'production') {
  const options = {
    key: fs.readFileSync(process.env.HTTPS_KEY_PATH),
    cert: fs.readFileSync(process.env.HTTPS_CERT_PATH),
  };
  https.createServer(options, app).listen(443, () => {
    console.log('Secure server running on port 443');
  });
} else {
  app.listen(3000, () => {
    console.log('Server running on port 3000 (development)');
  });
}

// Force HTTPS in production
if (process.env.NODE_ENV === 'production') {
  app.use((req, res, next) => {
    if (req.header('x-forwarded-proto') !== 'https') {
      res.redirect(`https://${req.header('host')}${req.url}`);
    } else {
      next();
    }
  });
}
```

---

### 7. **No Logging and Monitoring** (Medium)
**OWASP: A09:2021 – Logging and Monitoring Failures**

**Issue:** No security event logging, making incident detection impossible:

**Recommendation:**
```javascript
// ✅ CORRECT - Implement security logging
const winston = require('winston');

const logger = winston.createLogger({
  level: 'info',
