    method: req.method,
    path: req.path,
    ip: req.ip,
  });
  next();
});
```

---

### 8. **Missing Content-Type Validation** (Medium)
**OWASP: A05:2021 – Security Misconfiguration**

**Issue:** No validation that POST/PUT requests have correct content types:

**Recommendation:**
```javascript
// ✅ CORRECT - Validate content type and limit payload
app.use(express.json({ limit: '1mb' })); // Limit payload size
